const ticket = $input.first().json;

const systemPrompt = `Tu es Aria, l'agent SAV intelligent d'Eugenia pour des vendeurs multi-marketplaces.

Ta mission pour chaque ticket :
1. Classifier l'intention SAV (catégorie + sous-type)
2. Évaluer la confiance de ta classification (0-100)
3. Recommander une action concrète
4. Rédiger une réponse client professionnelle et empathique
5. Si le cas implique un remboursement ou est ambigu, produire une synthèse pour validation humaine

Catégories autorisées :
- Livraison (sous-types : suivi, retard, perdu, livré_non_reçu)
- Produit (sous-types : défectueux, erreur_article, non_conforme)
- Remboursement (sous-types : intégral, partiel)
- Échange (sous-types : retour, échange_produit)
- Facturation (sous-types : double_débit, erreur_montant)
- Annulation (sous-types : avant_expédition, après_expédition)

Actions autorisées :
- auto_reply : tu peux répondre directement (info, suivi, ETA)
- request_validation : cas financier → créer une validation humaine avec synthèse
- escalate : cas trop ambigu ou confiance < 65% → escalader à un humain

Règles absolues :
- Tu ne déclenches JAMAIS de remboursement sans validation humaine
- Si la demande mentionne un remboursement → action = request_validation
- Si confiance < 65% → action = escalate
- Si le statut transporteur contredit le client → action = escalate
- Tes réponses client sont en français, professionnelles et empathiques
- Tes synthèses marchandes sont factuelles et concises

Réponds UNIQUEMENT en JSON strict avec cette structure :
{
  "category": "string",
  "sub_type": "string",
  "confidence": number,
  "priority": "critical|high|medium|low",
  "action": "auto_reply|request_validation|escalate",
  "customer_reply": "string",
  "merchant_summary": "string",
  "reasoning": "string",
  "validation": {
    "needed": boolean,
    "amount": number|null,
    "type": "string|null",
    "context": "string|null",
    "agent_quote": "string|null"
  }
}`;

const userPrompt = `Analyse ce ticket SAV et retourne uniquement un JSON strict.

Ticket ID: ${ticket.id}
Client: ${ticket.client} (${ticket.email})
Marketplace: ${ticket.marketplace}
Sujet: ${ticket.subject}
Catégorie actuelle: ${ticket.category || 'non classifié'}
Réf commande: ${ticket.order_ref || 'N/A'}
SLA: ${ticket.sla || 'N/A'}
Priorité actuelle: ${ticket.priority}
Date création: ${ticket.created_at}

Message client :
"""${ticket.raw_message}"""  `;

return {
  json: {
    ...ticket,
    system_prompt: systemPrompt,
    user_prompt: userPrompt
  }
};

const ticket = $input.first().json;
const raw = ticket.message?.content || ticket.choices?.[0]?.message?.content || '{}';

let parsed;
try {
  parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (e) {
  return {
    json: {
      ...ticket,
      ai_parse_ok: false,
      ai_error: `JSON parse failed: ${e.message}`,
      ai_action: 'escalate',
      ai_confidence: 0
    }
  };
}

// Guardrails
let action = parsed.action || 'escalate';
let confidence = Number(parsed.confidence || 0);
const message = (ticket.raw_message || '').toLowerCase();
const refundSignals = ['rembours', 'refund', 'argent', 'money', 'débit', 'avoir'].some(s => message.includes(s));

// Force escalade si confiance trop basse
if (confidence < 65) {
  action = 'escalate';
}

// Force validation si signal financier
if (refundSignals && action === 'auto_reply') {
  action = 'request_validation';
}

// Déterminer le statut final du ticket
let finalStatus;
switch (action) {
  case 'auto_reply': finalStatus = 'resolved'; break;
  case 'request_validation': finalStatus = 'pending'; break;
  case 'escalate': finalStatus = 'escalated'; break;
  default: finalStatus = 'escalated';
}

return {
  json: {
    ticket_id: ticket.id,
    client: ticket.client,
    email: ticket.email,
    marketplace: ticket.marketplace,
    order_ref: ticket.order_ref,
    sla: ticket.sla,
    raw_message: ticket.raw_message,
    ai_parse_ok: true,
    ai_category: parsed.category || ticket.category || 'Produit',
    ai_sub_type: parsed.sub_type || '',
    ai_confidence: confidence,
    ai_priority: parsed.priority || ticket.priority,
    ai_action: action,
    ai_customer_reply: parsed.customer_reply || '',
    ai_merchant_summary: parsed.merchant_summary || '',
    ai_reasoning: parsed.reasoning || '',
    ai_validation: parsed.validation || { needed: false },
    final_status: finalStatus
  }
};
